        async function get_excel_content() {
    try {
        const config = {
            "sheet_name": pm.environment.get("gold_standard_sheetname"),
            "file_name": pm.environment.get("gold_standard_filename"),
        };
        const base64Result = await pm.executeAsync("analysis_excel.py", {
            "command": "python3",
            "args": ["analysis_excel.py", JSON.stringify(config)]
        });
        // 使用内置的 CryptoJS 进行解码，将 Base64 还原为 UTF-8 字符串，可以处理很长的字符串且不乱码
        const rawResult = CryptoJS.enc.Base64.parse(base64Result).toString(CryptoJS.enc.Utf8);

        const data = JSON.parse(rawResult);
        console.log("merged_result", JSON.stringify(data.merged_result))
        if (data.merged_result) {
            pm.environment.set("goldStandardData", JSON.stringify(data.merged_result));
            pm.environment.set("file_count", JSON.stringify(data.file_count));
            pm.environment.set("task_queue", "[]");
            console.log(`✅ 加载成功: ${data.file_count} 个文件`);
        }
    } catch (error) {
        console.error("❌ 提取失败，请检查 Base64 解码或 Python 逻辑:", error);
    }
}
